import{_ as t,c as e,d,o}from"./index-CyFxHz-O.js";const s={},r={class:"doc-page"};function n(i,a){return o(),e("div",r,[...a[0]||(a[0]=[d(`<div class="doc-masthead" data-v-66a86e0f><h1 data-v-66a86e0f>CloudRadar Documentation</h1><p class="doc-intro" data-v-66a86e0f> Complete reference for CloudRadar — from first-time setup to every scan, report, and new feature. Use the table of contents to jump to any section. </p><div class="version-badge" data-v-66a86e0f>v2.0 — Updated with all latest features</div></div><nav class="doc-toc" data-v-66a86e0f><div class="toc-group" data-v-66a86e0f><span class="toc-group-label" data-v-66a86e0f>Getting started</span><a href="#getting-started" data-v-66a86e0f>Overview</a><a href="#cloud-selection" data-v-66a86e0f>Cloud selection</a><a href="#setup" data-v-66a86e0f>Credentials setup</a></div><div class="toc-group" data-v-66a86e0f><span class="toc-group-label" data-v-66a86e0f>New features</span><a href="#dashboard" data-v-66a86e0f>Dashboard &amp; charts</a><a href="#command-palette" data-v-66a86e0f>Command palette (Ctrl+K)</a><a href="#findings-slideover" data-v-66a86e0f>Findings slide-over panel</a><a href="#recommendations" data-v-66a86e0f>Per-finding recommendations</a><a href="#scan-history" data-v-66a86e0f>Scan history</a><a href="#post-scan-summary" data-v-66a86e0f>Post-scan summary card</a><a href="#compliance-gaps" data-v-66a86e0f>Compliance gap analysis</a><a href="#toast" data-v-66a86e0f>Toast notifications</a><a href="#sidebar-features" data-v-66a86e0f>Sidebar features</a><a href="#mobile" data-v-66a86e0f>Mobile support</a></div><div class="toc-group" data-v-66a86e0f><span class="toc-group-label" data-v-66a86e0f>Scans &amp; reports</span><a href="#security" data-v-66a86e0f>Security scan</a><a href="#vulnerabilities" data-v-66a86e0f>Vulnerabilities</a><a href="#audit" data-v-66a86e0f>Audit</a><a href="#compliance" data-v-66a86e0f>Compliance</a><a href="#governance" data-v-66a86e0f>Governance</a><a href="#pentest" data-v-66a86e0f>Pentest</a><a href="#tests" data-v-66a86e0f>Tests</a><a href="#hosting" data-v-66a86e0f>Running CloudRadar</a></div></nav><section class="doc-section" id="getting-started" data-v-66a86e0f><h2 data-v-66a86e0f>Overview</h2><p data-v-66a86e0f><strong data-v-66a86e0f>CloudRadar</strong> is a multi-cloud Security Posture Management (CSPM) platform. It discovers resources in <strong data-v-66a86e0f>AWS, Google Cloud, and Azure</strong>; evaluates security rules; checks compliance against CIS / SOC 2 / HIPAA / PCI DSS / ISO 27001; and produces findings, charts, recommendations, and pentest output — all from a single browser UI. </p><div class="tip-box" data-v-66a86e0f><span class="tip-icon" data-v-66a86e0f>💡</span><span data-v-66a86e0f>Click the <strong data-v-66a86e0f>CloudRadar logo</strong> in the top-left of the sidebar at any time to return to the cloud-selection screen.</span></div><div class="feature-grid" data-v-66a86e0f><div class="feature-card" data-v-66a86e0f><span class="feat-emoji" data-v-66a86e0f>📊</span><strong data-v-66a86e0f>Dashboard with charts</strong><span data-v-66a86e0f>Real-time risk score, severity donut chart, trend line, and scan history bar chart — per cloud provider.</span></div><div class="feature-card" data-v-66a86e0f><span class="feat-emoji" data-v-66a86e0f>⌨️</span><strong data-v-66a86e0f>Command palette</strong><span data-v-66a86e0f>Press Ctrl+K anywhere to instantly navigate to any page or action.</span></div><div class="feature-card" data-v-66a86e0f><span class="feat-emoji" data-v-66a86e0f>📋</span><strong data-v-66a86e0f>Findings slide-over</strong><span data-v-66a86e0f>Click any finding for a detailed panel with what/why/how-to-fix and AWS docs link.</span></div><div class="feature-card" data-v-66a86e0f><span class="feat-emoji" data-v-66a86e0f>📅</span><strong data-v-66a86e0f>Scan history</strong><span data-v-66a86e0f>Every completed scan is saved automatically — browse, filter and compare past runs.</span></div><div class="feature-card" data-v-66a86e0f><span class="feat-emoji" data-v-66a86e0f>✅</span><strong data-v-66a86e0f>Compliance gap analysis</strong><span data-v-66a86e0f>Failed compliance controls now include specific remediation steps, not just a pass/fail status.</span></div><div class="feature-card" data-v-66a86e0f><span class="feat-emoji" data-v-66a86e0f>📱</span><strong data-v-66a86e0f>Mobile support</strong><span data-v-66a86e0f>Hamburger menu and responsive layout work on phones and tablets.</span></div></div></section><section class="doc-section" id="cloud-selection" data-v-66a86e0f><h2 data-v-66a86e0f>Cloud selection</h2><p data-v-66a86e0f> The first screen shows three cloud provider cards: <strong data-v-66a86e0f>AWS</strong>, <strong data-v-66a86e0f>Google Cloud</strong>, and <strong data-v-66a86e0f>Azure</strong>. Click the one that matches your environment to be taken to the Setup page. You can switch cloud provider at any time from the sidebar Setup link. </p><div class="tip-box" data-v-66a86e0f><span class="tip-icon" data-v-66a86e0f>ℹ️</span><span data-v-66a86e0f>CloudRadar stores your selected cloud in browser storage so the Dashboard will remember it on your next visit.</span></div></section><section class="doc-section" id="setup" data-v-66a86e0f><h2 data-v-66a86e0f>Setup &amp; credentials</h2><p data-v-66a86e0f>Credentials are stored in <code data-v-66a86e0f>config.yaml</code> in the project root. Restrict file permissions and never commit this file to version control.</p><table class="doc-table" data-v-66a86e0f><thead data-v-66a86e0f><tr data-v-66a86e0f><th data-v-66a86e0f>Cloud</th><th data-v-66a86e0f>Required fields</th><th data-v-66a86e0f>Notes</th></tr></thead><tbody data-v-66a86e0f><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>AWS</strong></td><td data-v-66a86e0f>Region, Access Key ID, Secret Access Key</td><td data-v-66a86e0f>Session Token optional (for temporary credentials). Prefer IAM roles or AWS profiles over long-lived keys.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>GCP</strong></td><td data-v-66a86e0f>Project ID</td><td data-v-66a86e0f>Service account JSON path optional — leave blank to use <code data-v-66a86e0f>gcloud auth application-default login</code>.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Azure</strong></td><td data-v-66a86e0f>Subscription ID, Tenant ID, Client ID, Client secret</td><td data-v-66a86e0f>Create a service principal with Reader + Security Reader roles on the subscription.</td></tr></tbody></table><p data-v-66a86e0f>Click <strong data-v-66a86e0f>Save and continue</strong> to persist credentials or <strong data-v-66a86e0f>Setup later</strong> to skip and use environment variables.</p></section><section class="doc-section" id="dashboard" data-v-66a86e0f><h2 data-v-66a86e0f>🆕 Dashboard with charts &amp; cloud tabs</h2><p data-v-66a86e0f> The Dashboard has been completely redesigned. It now shows live data per cloud provider and includes interactive Chart.js charts. </p><h3 data-v-66a86e0f>Cloud tabs (AWS / Google Cloud / Azure)</h3><p data-v-66a86e0f> Three tabs sit at the top of the Dashboard — one for each cloud provider. Clicking a tab switches <em data-v-66a86e0f>all</em> data on the page (KPI cards, charts, and recommendations) to that cloud&#39;s scan history. The tab badge shows how many scans have been recorded for that provider. </p><h3 data-v-66a86e0f>KPI cards</h3><table class="doc-table" data-v-66a86e0f><thead data-v-66a86e0f><tr data-v-66a86e0f><th data-v-66a86e0f>Card</th><th data-v-66a86e0f>What it shows</th></tr></thead><tbody data-v-66a86e0f><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Last scan</strong></td><td data-v-66a86e0f>How long ago the most recent scan for the selected cloud ran, with cloud name and region.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Total findings</strong></td><td data-v-66a86e0f>Number of security findings from the latest scan of the selected cloud.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Risk score</strong></td><td data-v-66a86e0f>Numeric risk score colour-coded: green (low) → yellow (medium) → orange (high) → red (critical).</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Critical</strong></td><td data-v-66a86e0f>Count of critical-severity findings that need immediate remediation.</td></tr></tbody></table><h3 data-v-66a86e0f>Charts</h3><table class="doc-table" data-v-66a86e0f><thead data-v-66a86e0f><tr data-v-66a86e0f><th data-v-66a86e0f>Chart</th><th data-v-66a86e0f>Type</th><th data-v-66a86e0f>What it shows</th></tr></thead><tbody data-v-66a86e0f><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Findings by severity</strong></td><td data-v-66a86e0f>Donut chart</td><td data-v-66a86e0f>Distribution of Critical / High / Medium / Low findings from the latest scan. Total finding count shown in the centre.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Risk score over time</strong></td><td data-v-66a86e0f>Line chart</td><td data-v-66a86e0f>Risk score trend across the last 10 scans for the selected cloud. Requires at least 2 recorded scans.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Findings per scan</strong></td><td data-v-66a86e0f>Stacked bar chart</td><td data-v-66a86e0f>Breakdown of severity counts per scan run for the last 8 scans. Each bar is stacked Critical / High / Medium / Low.</td></tr></tbody></table><h3 data-v-66a86e0f>Top recommendations panel</h3><p data-v-66a86e0f> Immediately below the charts, the Dashboard shows the <strong data-v-66a86e0f>5 highest-priority recommendations</strong> for the current cloud provider, derived from the severity profile of the latest scan. Each recommendation shows: </p><ul data-v-66a86e0f><li data-v-66a86e0f>A <strong data-v-66a86e0f>title</strong> and <strong data-v-66a86e0f>severity badge</strong></li><li data-v-66a86e0f>A plain-English <em data-v-66a86e0f>&quot;What is this?&quot;</em> description</li><li data-v-66a86e0f>The first (most important) fix step</li><li data-v-66a86e0f>A direct link to the cloud provider&#39;s official documentation</li></ul><p data-v-66a86e0f> Recommendations are <strong data-v-66a86e0f>cloud-specific</strong>: </p><ul data-v-66a86e0f><li data-v-66a86e0f><strong data-v-66a86e0f>AWS</strong> — e.g. &quot;SSH port 22 open to the world&quot;, &quot;S3 bucket publicly accessible&quot;, &quot;IAM wildcard action&quot;</li><li data-v-66a86e0f><strong data-v-66a86e0f>Google Cloud</strong> — e.g. &quot;Firewall rule allows SSH from 0.0.0.0/0&quot;, &quot;GCS bucket public&quot;, &quot;IAM primitive roles in use&quot;</li><li data-v-66a86e0f><strong data-v-66a86e0f>Azure</strong> — e.g. &quot;NSG allows RDP from any IP&quot;, &quot;Storage account allows public blob access&quot;, &quot;Azure AD users without MFA&quot;</li></ul><p data-v-66a86e0f>If no scans have been run for a cloud yet, an empty state with a &quot;Run Scan&quot; button is shown instead.</p><h3 data-v-66a86e0f>Quick actions &amp; connection status</h3><p data-v-66a86e0f> The bottom of the Dashboard shows 8 quick-action tiles for the most common tasks, plus a <strong data-v-66a86e0f>cloud connection status card</strong> showing whether credentials are configured for the selected provider (region for AWS, project ID for GCP, subscription ID for Azure). </p></section><section class="doc-section" id="command-palette" data-v-66a86e0f><h2 data-v-66a86e0f>🆕 Command palette (Ctrl+K)</h2><p data-v-66a86e0f> The command palette lets you navigate anywhere in CloudRadar instantly — without touching the sidebar or mouse. </p><h3 data-v-66a86e0f>How to use it</h3><ol data-v-66a86e0f><li data-v-66a86e0f>Press <kbd data-v-66a86e0f>Ctrl+K</kbd> (Windows/Linux) or <kbd data-v-66a86e0f>Cmd+K</kbd> (Mac) from <em data-v-66a86e0f>any page</em>.</li><li data-v-66a86e0f>Start typing — the palette instantly filters by page name or section.</li><li data-v-66a86e0f>Use <kbd data-v-66a86e0f>↑</kbd> / <kbd data-v-66a86e0f>↓</kbd> arrow keys to move through results.</li><li data-v-66a86e0f>Press <kbd data-v-66a86e0f>Enter</kbd> to navigate to the highlighted item.</li><li data-v-66a86e0f>Press <kbd data-v-66a86e0f>Esc</kbd> or click outside to close without navigating.</li></ol><p data-v-66a86e0f>The palette covers all 18 pages: Dashboard, Security Scan, Vulnerabilities, Findings, Attack Paths, Scheduled Scans, Notifications, List Assets, Changes, Snapshot Diff, Audit Logs, Scan History, Compliance, Governance, Pentest, Tests, Setup, and Documentation.</p><div class="tip-box" data-v-66a86e0f><span class="tip-icon" data-v-66a86e0f>💡</span><span data-v-66a86e0f>The hint <kbd data-v-66a86e0f>Ctrl+K</kbd> is also displayed at the bottom of the Quick actions section on the Dashboard.</span></div></section><section class="doc-section" id="findings-slideover" data-v-66a86e0f><h2 data-v-66a86e0f>🆕 Findings detail slide-over panel</h2><p data-v-66a86e0f> The Findings page now has a <strong data-v-66a86e0f>right-side slide-over panel</strong>. Click any row in the findings table to open it without leaving the page. </p><h3 data-v-66a86e0f>What the panel shows</h3><table class="doc-table" data-v-66a86e0f><thead data-v-66a86e0f><tr data-v-66a86e0f><th data-v-66a86e0f>Section</th><th data-v-66a86e0f>Content</th></tr></thead><tbody data-v-66a86e0f><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Metadata</strong></td><td data-v-66a86e0f>Rule ID, resource type, resource ID, region — in a clean grid layout.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>What is this?</strong></td><td data-v-66a86e0f>Plain-English explanation of the security issue.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Why it matters</strong></td><td data-v-66a86e0f>Explanation of the real-world risk and how attackers exploit it.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>How to fix it</strong></td><td data-v-66a86e0f>Step-by-step numbered remediation instructions specific to the finding type.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>AWS Docs link</strong></td><td data-v-66a86e0f>Direct link to the relevant official documentation page.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Raw JSON</strong></td><td data-v-66a86e0f>Collapsible section showing the full raw finding object for debugging.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Auto-remediation</strong></td><td data-v-66a86e0f>For supported resource types (S3, IAM roles, security groups) — dry-run or apply fix directly from the panel.</td></tr></tbody></table><h3 data-v-66a86e0f>Filtering the findings table</h3><p data-v-66a86e0f>Before clicking a row, you can narrow the list with three filters:</p><ul data-v-66a86e0f><li data-v-66a86e0f><strong data-v-66a86e0f>Search box</strong> — filters by rule ID, resource type, resource ID, or title</li><li data-v-66a86e0f><strong data-v-66a86e0f>Severity dropdown</strong> — show only Critical / High / Medium / Low</li><li data-v-66a86e0f><strong data-v-66a86e0f>Resource type dropdown</strong> — filter to a specific service (e.g. <code data-v-66a86e0f>s3</code>, <code data-v-66a86e0f>security_group</code>)</li></ul><p data-v-66a86e0f>The <strong data-v-66a86e0f>Export CSV</strong> button exports the currently filtered list.</p></section><section class="doc-section" id="recommendations" data-v-66a86e0f><h2 data-v-66a86e0f>🆕 Per-finding recommendation library</h2><p data-v-66a86e0f> CloudRadar now includes a built-in recommendation library with <strong data-v-66a86e0f>60+ rule mappings</strong> covering all three cloud providers. Every finding is matched to a recommendation that includes: what the issue is, why it is dangerous, how to fix it (step by step), and a link to official docs. </p><h3 data-v-66a86e0f>AWS rules covered</h3><p data-v-66a86e0f>EC2 (public IP, vulnerable AMI, missing tags) · S3 (public access, no encryption, no versioning) · IAM (wildcard actions, admin policy, unused keys) · Security Groups (SSH open, RDP open, all traffic) · RDS (public, no encryption) · Lambda (hardcoded secrets) · CloudTrail (disabled) · EBS (unencrypted) · EKS (public endpoint) · GuardDuty (disabled) · KMS (no rotation) · VPC (default VPC, no flow logs) · ALB (no WAF, no access logs) · DynamoDB (no PITR) · ECR (critical CVEs, no scan-on-push)</p><h3 data-v-66a86e0f>Google Cloud rules covered</h3><p data-v-66a86e0f>Compute Engine (public IP, serial port, OS patching) · Cloud Storage (public bucket, no CMEK, no versioning) · IAM (service account keys, primitive roles, no MFA) · Firewall (SSH open, RDP open) · VPC (no flow logs) · Cloud SQL (public IP, no backup) · GKE (public endpoint, legacy ABAC) · Cloud Audit Logging (disabled) · Cloud Monitoring (no alerts) · Cloud KMS (no rotation)</p><h3 data-v-66a86e0f>Azure rules covered</h3><p data-v-66a86e0f>Virtual Machines (public IP, no disk encryption, no Defender for Endpoint) · Storage Accounts (public blob, no HTTPS, no CMK) · Azure AD (no MFA, excessive permissions, no PIM) · NSG (SSH open, RDP open) · Azure SQL (public access, no TDE, no auditing) · Key Vault (no expiry, no soft delete) · Azure Monitor (activity log not retained) · Defender for Cloud (not enabled) · AKS (public endpoint, RBAC disabled)</p><div class="tip-box" data-v-66a86e0f><span class="tip-icon" data-v-66a86e0f>ℹ️</span><span data-v-66a86e0f>Recommendations are matched automatically — first by exact <code data-v-66a86e0f>rule_id</code>, then by <code data-v-66a86e0f>resource_type</code> prefix. Unrecognised findings fall back to a generic cloud-appropriate recommendation.</span></div></section><section class="doc-section" id="scan-history" data-v-66a86e0f><h2 data-v-66a86e0f>🆕 Scan history</h2><p data-v-66a86e0f> Every completed scan is automatically saved to browser storage. The <strong data-v-66a86e0f>Scan History</strong> page (accessible from the Audit group in the sidebar or via Ctrl+K → &quot;Scan History&quot;) shows a full table of all recorded scans. </p><h3 data-v-66a86e0f>Table columns</h3><table class="doc-table" data-v-66a86e0f><thead data-v-66a86e0f><tr data-v-66a86e0f><th data-v-66a86e0f>Column</th><th data-v-66a86e0f>Description</th></tr></thead><tbody data-v-66a86e0f><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Date &amp; Time</strong></td><td data-v-66a86e0f>When the scan ran.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Cloud</strong></td><td data-v-66a86e0f>AWS / GCP / Azure badge.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Region / Project</strong></td><td data-v-66a86e0f>The region or project ID scanned.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Findings</strong></td><td data-v-66a86e0f>Total number of security findings.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Risk score</strong></td><td data-v-66a86e0f>Colour-coded risk score badge.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Critical / High</strong></td><td data-v-66a86e0f>Count of the two most urgent severity levels.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Duration</strong></td><td data-v-66a86e0f>Scan duration in seconds.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Status</strong></td><td data-v-66a86e0f>Completed / Failed / Running.</td></tr></tbody></table><h3 data-v-66a86e0f>Slide-over detail view</h3><p data-v-66a86e0f>Click any row to open a detail panel showing a severity breakdown bar chart for that scan, plus a link to view the current findings.</p><h3 data-v-66a86e0f>Storage and limits</h3><ul data-v-66a86e0f><li data-v-66a86e0f>Up to <strong data-v-66a86e0f>100 scan records</strong> are stored in <code data-v-66a86e0f>localStorage</code>. Oldest records are automatically removed when the limit is reached.</li><li data-v-66a86e0f>Data is stored in the browser — clearing browser storage or using a different browser will start fresh.</li><li data-v-66a86e0f>Use the <strong data-v-66a86e0f>Clear history</strong> button (with confirmation) to wipe all records.</li></ul></section><section class="doc-section" id="post-scan-summary" data-v-66a86e0f><h2 data-v-66a86e0f>🆕 Post-scan summary card</h2><p data-v-66a86e0f> After a Security Scan completes, instead of raw JSON output, a structured <strong data-v-66a86e0f>summary card</strong> is displayed at the bottom of the progress log. </p><h3 data-v-66a86e0f>The summary card includes</h3><ul data-v-66a86e0f><li data-v-66a86e0f><strong data-v-66a86e0f>Severity pills</strong> — 🔴 N Critical · 🟠 N High · 🟡 N Medium · 🟢 N Low (or &quot;✅ No findings&quot; if clean)</li><li data-v-66a86e0f><strong data-v-66a86e0f>Risk score badge</strong> — colour-coded and labelled (critical / high risk / medium risk / low risk)</li><li data-v-66a86e0f><strong data-v-66a86e0f>Scan metadata</strong> — cloud provider, region, total findings count</li><li data-v-66a86e0f><strong data-v-66a86e0f>Top 3 recommended actions</strong> — cloud-specific recommendations ranked by severity, each showing the title, first fix step, and severity badge</li><li data-v-66a86e0f><strong data-v-66a86e0f>Action buttons</strong> — &quot;View All Findings →&quot; and any download links returned by the scan</li></ul><div class="tip-box" data-v-66a86e0f><span class="tip-icon" data-v-66a86e0f>💡</span><span data-v-66a86e0f>The recommendations shown in the summary card are <strong data-v-66a86e0f>cloud-aware</strong>. A GCP scan shows GCP-specific recommendations; an Azure scan shows Azure-specific ones.</span></div></section><section class="doc-section" id="compliance-gaps" data-v-66a86e0f><h2 data-v-66a86e0f>🆕 Compliance gap analysis</h2><p data-v-66a86e0f> The Compliance page has been upgraded. When you run a check with <strong data-v-66a86e0f>JSON + Suggestions</strong> output selected, the result is now a structured report with gap analysis — not just raw JSON. </p><h3 data-v-66a86e0f>Compliance summary strip</h3><p data-v-66a86e0f>Four cards show: <strong data-v-66a86e0f>Passed</strong> count, <strong data-v-66a86e0f>Failed</strong> count, overall <strong data-v-66a86e0f>Compliance %</strong> (colour-coded), and the selected <strong data-v-66a86e0f>Framework</strong>. A progress bar visualises the compliance percentage.</p><h3 data-v-66a86e0f>Failed controls — gap analysis</h3><p data-v-66a86e0f> Each failed control appears in an expandable row. Click the row to see: </p><ul data-v-66a86e0f><li data-v-66a86e0f>The control description / reason for failure</li><li data-v-66a86e0f>A <strong data-v-66a86e0f>gap recommendation</strong> automatically matched to the control — includes what to do, step-by-step fix instructions, and a link to official documentation</li></ul><p data-v-66a86e0f>Controls are matched to recommendations using keyword mapping against the control ID and name (e.g. a control mentioning &quot;CloudTrail&quot; maps to the CloudTrail disabled recommendation; a control mentioning &quot;S3 encrypt&quot; maps to the S3 encryption recommendation).</p><h3 data-v-66a86e0f>Passed controls</h3><p data-v-66a86e0f>All passing controls are shown in a collapsible section beneath the failed ones.</p><h3 data-v-66a86e0f>Raw JSON toggle</h3><p data-v-66a86e0f>The full raw API response is always available via a collapsible &quot;Raw JSON response&quot; section at the bottom.</p><h3 data-v-66a86e0f>How to use</h3><ol data-v-66a86e0f><li data-v-66a86e0f>Go to <strong data-v-66a86e0f>Compliance</strong> in the sidebar.</li><li data-v-66a86e0f>Select a framework (CIS, SOC 2, HIPAA, PCI DSS, or ISO 27001).</li><li data-v-66a86e0f>Select <strong data-v-66a86e0f>JSON + Suggestions</strong> as the output format.</li><li data-v-66a86e0f>Click <strong data-v-66a86e0f>Run compliance check</strong>.</li><li data-v-66a86e0f>Review the summary, then expand any failed control for specific remediation guidance.</li></ol></section><section class="doc-section" id="toast" data-v-66a86e0f><h2 data-v-66a86e0f>🆕 Toast notification system</h2><p data-v-66a86e0f> A global toast notification layer is now active across the application. Toasts appear in the <strong data-v-66a86e0f>bottom-right corner</strong> of the screen and automatically dismiss after a few seconds. </p><table class="doc-table" data-v-66a86e0f><thead data-v-66a86e0f><tr data-v-66a86e0f><th data-v-66a86e0f>Type</th><th data-v-66a86e0f>Colour</th><th data-v-66a86e0f>Used for</th><th data-v-66a86e0f>Auto-dismiss</th></tr></thead><tbody data-v-66a86e0f><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Success</strong></td><td data-v-66a86e0f>Green</td><td data-v-66a86e0f>Completed actions (scan started, CSV exported, etc.)</td><td data-v-66a86e0f>4 seconds</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Error</strong></td><td data-v-66a86e0f>Red</td><td data-v-66a86e0f>Failed operations, API errors</td><td data-v-66a86e0f>6 seconds</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Warning</strong></td><td data-v-66a86e0f>Amber</td><td data-v-66a86e0f>Non-critical issues requiring attention</td><td data-v-66a86e0f>4 seconds</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Info</strong></td><td data-v-66a86e0f>Blue</td><td data-v-66a86e0f>Informational messages</td><td data-v-66a86e0f>4 seconds</td></tr></tbody></table><p data-v-66a86e0f>Multiple toasts can stack. Click any toast to dismiss it immediately.</p></section><section class="doc-section" id="sidebar-features" data-v-66a86e0f><h2 data-v-66a86e0f>🆕 Sidebar features</h2><h3 data-v-66a86e0f>Collapse / expand</h3><p data-v-66a86e0f>Click the <strong data-v-66a86e0f>arrow button</strong> in the top-right of the sidebar to collapse it to icon-only mode. Click again to expand. The state is remembered across browser sessions. The main content area smoothly adjusts its margin.</p><h3 data-v-66a86e0f>Collapsible navigation groups</h3><p data-v-66a86e0f>Each navigation section (Security, Audit, Compliance, Governance, Pentest, Tests) has a <strong data-v-66a86e0f>▾ arrow toggle</strong> on the right. Click the group header to collapse or expand its links. Group states are saved in browser storage — your preferred layout is remembered between visits.</p><h3 data-v-66a86e0f>User profile</h3><p data-v-66a86e0f>The bottom of the sidebar shows a user avatar with auto-generated initials and a colour derived from your name. Click the edit icon to change your display name. The name is saved in browser storage.</p><h3 data-v-66a86e0f>Audit Logs</h3><p data-v-66a86e0f>The <strong data-v-66a86e0f>Audit Logs</strong> page (under the Audit group) records who ran what and when. Logs are stored in browser storage and can be filtered by user, status, and keyword, then exported to CSV or cleared.</p><h3 data-v-66a86e0f>Scan History in sidebar</h3><p data-v-66a86e0f>The <strong data-v-66a86e0f>Scan History</strong> link now appears in the Audit group, giving quick access to the full scan history table from anywhere.</p><h3 data-v-66a86e0f>Theme toggle</h3><p data-v-66a86e0f>The sun ☀ / moon 🌙 buttons at the bottom of the sidebar toggle between dark and light mode. The choice is saved in browser storage.</p></section><section class="doc-section" id="mobile" data-v-66a86e0f><h2 data-v-66a86e0f>🆕 Mobile &amp; responsive support</h2><p data-v-66a86e0f> CloudRadar now works on mobile phones and tablets. </p><ul data-v-66a86e0f><li data-v-66a86e0f>On screens narrower than <strong data-v-66a86e0f>768 px</strong>, the sidebar is hidden by default.</li><li data-v-66a86e0f>A <strong data-v-66a86e0f>hamburger button ☰</strong> appears in the top-left corner to open the sidebar as an overlay.</li><li data-v-66a86e0f>A <strong data-v-66a86e0f>dark backdrop</strong> covers the main content while the sidebar is open — tap it to close.</li><li data-v-66a86e0f>The main content padding and layout adjust automatically for small screens.</li></ul></section><section class="doc-section" id="security" data-v-66a86e0f><h2 data-v-66a86e0f>Security — Full security scan</h2><p data-v-66a86e0f> The <strong data-v-66a86e0f>Security Scan</strong> runs end-to-end discovery, enrichment, rule evaluation, risk scoring, and optionally saves a snapshot. Progress is shown step-by-step in real time. After completion, a <strong data-v-66a86e0f>structured summary card</strong> replaces the raw JSON output (see <a href="#post-scan-summary" data-v-66a86e0f>Post-scan summary card</a>). </p><p data-v-66a86e0f>Select which services to scan using the script selector. Deselecting a service skips all its API calls — useful for faster, cheaper targeted scans.</p><h3 data-v-66a86e0f>Services &amp; what is checked</h3><table class="doc-table" data-v-66a86e0f><thead data-v-66a86e0f><tr data-v-66a86e0f><th data-v-66a86e0f>Service</th><th data-v-66a86e0f>Script ID</th><th data-v-66a86e0f>What is checked</th></tr></thead><tbody data-v-66a86e0f><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>EC2</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>ec2</code></td><td data-v-66a86e0f>Public IPs, vulnerable AMIs, instance types, missing required tags.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>S3</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>s3</code></td><td data-v-66a86e0f>Public-access-block disabled, missing server-side encryption, overly permissive bucket policies.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>RDS</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>rds</code></td><td data-v-66a86e0f>Publicly accessible flag, storage encryption at rest disabled.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Lambda</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>lambda</code></td><td data-v-66a86e0f>Short or missing timeout, hardcoded secrets in env vars, missing tags.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>IAM</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>iam</code></td><td data-v-66a86e0f>Wildcard actions in policies, admin-policy attachments, unused access keys.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Security Groups</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>sg</code></td><td data-v-66a86e0f>Inbound rules open to 0.0.0.0/0 on ports 22, 3389, 3306, 5432, 1433, and others.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>ALB</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>alb</code></td><td data-v-66a86e0f>Internet-facing ALBs missing WAF Web ACL, access logging disabled.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>WAF</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>waf</code></td><td data-v-66a86e0f>Web ACLs not associated with API Gateway or ALB resources.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>CloudTrail</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>cloudtrail</code></td><td data-v-66a86e0f>Multi-region not enabled, log file validation off, CloudWatch integration missing.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>VPC</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>vpc</code></td><td data-v-66a86e0f>Default VPC still in use, VPC flow logs not enabled.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>EBS Volumes</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>ebs</code></td><td data-v-66a86e0f>Volumes without encryption at rest.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>EKS</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>eks</code></td><td data-v-66a86e0f>Public API server endpoint, control plane logging disabled, secrets encryption missing.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>ECS</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>ecs</code></td><td data-v-66a86e0f>Privileged containers, missing CloudWatch log config, containers running as root.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>KMS</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>kms</code></td><td data-v-66a86e0f>Customer-managed keys with automatic rotation disabled.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>API Gateway</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>apigateway</code></td><td data-v-66a86e0f>Access logging not enabled, WAF not attached to REST API stages.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>SQS</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>sqs</code></td><td data-v-66a86e0f>Queues without server-side encryption, public resource policy exposure.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>DynamoDB</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>dynamodb</code></td><td data-v-66a86e0f>Tables without encryption at rest, PITR disabled.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>GuardDuty</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>guardduty</code></td><td data-v-66a86e0f>Threat detection detector not enabled in the scanned region.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>CloudWatch</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>cloudwatch</code></td><td data-v-66a86e0f>Missing CIS metric filters for root login, IAM/CloudTrail/VPC/KMS/S3 changes.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>ECR</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>ecr</code></td><td data-v-66a86e0f>Container images with critical/high CVEs, scan-on-push not enabled.</td></tr></tbody></table></section><section class="doc-section" id="vulnerabilities" data-v-66a86e0f><h2 data-v-66a86e0f>Security — Vulnerabilities</h2><p data-v-66a86e0f>A focused scan for known CVEs and AMI issues without running the full CSPM rule engine.</p><table class="doc-table" data-v-66a86e0f><thead data-v-66a86e0f><tr data-v-66a86e0f><th data-v-66a86e0f>Script</th><th data-v-66a86e0f>ID</th><th data-v-66a86e0f>What it does</th></tr></thead><tbody data-v-66a86e0f><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>ECR Image Scan</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>ecr</code></td><td data-v-66a86e0f>Pulls all ECR repositories and checks each image tag for CVE findings. Reports critical and high severity CVEs with package name, version, and fix version where available.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>AMI Vulnerability Check</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>ami</code></td><td data-v-66a86e0f>Checks EC2 instances for deprecated AMIs (older than 180 days), public AMI usage, and known-vulnerable AMI IDs.</td></tr></tbody></table></section><section class="doc-section" id="audit" data-v-66a86e0f><h2 data-v-66a86e0f>Audit</h2><p data-v-66a86e0f>Audit scripts let you inspect and compare your asset catalog over time. They do not run security rules.</p><table class="doc-table" data-v-66a86e0f><thead data-v-66a86e0f><tr data-v-66a86e0f><th data-v-66a86e0f>Page</th><th data-v-66a86e0f>What it does</th><th data-v-66a86e0f>Options</th></tr></thead><tbody data-v-66a86e0f><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>List assets</strong></td><td data-v-66a86e0f>Exports the full asset catalog from the last scan (or a named snapshot) as JSON or CSV. Includes resource type, ID, region, tags, and risk-score field.</td><td data-v-66a86e0f>Output format (JSON / CSV); Snapshot ID (optional).</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Changes</strong></td><td data-v-66a86e0f>Compares the current cloud state with the last saved snapshot. Reports added, removed, and modified resources.</td><td data-v-66a86e0f>Runs automatically from latest scan vs. previous snapshot.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Snapshot diff</strong></td><td data-v-66a86e0f>Compares two named snapshots by ID. Shows the exact diff between any two points in time.</td><td data-v-66a86e0f>Snapshot ID A and Snapshot ID B.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Audit Logs</strong></td><td data-v-66a86e0f>Browser-local log of who ran what action and when. Searchable, filterable, and exportable.</td><td data-v-66a86e0f>Filter by user, status, or text. Export CSV. Clear all logs.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Scan History</strong></td><td data-v-66a86e0f>All completed scans recorded in browser storage with severity breakdown and risk scores.</td><td data-v-66a86e0f>Click any row for a detail slide-over. Clear history button.</td></tr></tbody></table></section><section class="doc-section" id="compliance" data-v-66a86e0f><h2 data-v-66a86e0f>Compliance</h2><p data-v-66a86e0f>Maps security findings to framework controls and generates a pass/fail report with remediation guidance. The check uses findings from the latest scan (or triggers a new scan if no data exists).</p><table class="doc-table" data-v-66a86e0f><thead data-v-66a86e0f><tr data-v-66a86e0f><th data-v-66a86e0f>Framework</th><th data-v-66a86e0f>Standard</th><th data-v-66a86e0f>Focus</th></tr></thead><tbody data-v-66a86e0f><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>CIS</strong></td><td data-v-66a86e0f>CIS AWS Foundations Benchmark v1.5</td><td data-v-66a86e0f>IAM password policy, MFA on root, CloudTrail enabled, VPC flow logs, S3 logging, CloudWatch alarms.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>SOC 2</strong></td><td data-v-66a86e0f>AICPA SOC 2 Trust Services Criteria</td><td data-v-66a86e0f>Logical access controls, encryption in transit and at rest, monitoring, incident response readiness.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>HIPAA</strong></td><td data-v-66a86e0f>HIPAA Security Rule (45 CFR Part 164)</td><td data-v-66a86e0f>Access control, audit controls, integrity, transmission security, encryption of PHI at rest and in transit.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>PCI DSS</strong></td><td data-v-66a86e0f>PCI DSS v4.0</td><td data-v-66a86e0f>Firewall rules, no default credentials, encryption of cardholder data, access control, monitoring &amp; logging.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>ISO 27001</strong></td><td data-v-66a86e0f>ISO/IEC 27001:2022 Annex A</td><td data-v-66a86e0f>A.5 policies, A.6 people controls, A.8 asset management, A.8.20 network security, A.8.24 cryptography, A.8.15 logging.</td></tr></tbody></table><div class="tip-box" data-v-66a86e0f><span class="tip-icon" data-v-66a86e0f>🆕</span><span data-v-66a86e0f>Select <strong data-v-66a86e0f>JSON + Suggestions</strong> as the output format to get per-control gap analysis with specific remediation steps. See <a href="#compliance-gaps" data-v-66a86e0f>Compliance gap analysis</a> for full details.</span></div></section><section class="doc-section" id="governance" data-v-66a86e0f><h2 data-v-66a86e0f>Governance</h2><p data-v-66a86e0f>Governance checks enforce your organisation&#39;s resource policies and tagging standards.</p><table class="doc-table" data-v-66a86e0f><thead data-v-66a86e0f><tr data-v-66a86e0f><th data-v-66a86e0f>Script</th><th data-v-66a86e0f>ID</th><th data-v-66a86e0f>What it does</th></tr></thead><tbody data-v-66a86e0f><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Tag Compliance</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>tags</code></td><td data-v-66a86e0f>Scans all resources for required tags (e.g. <code data-v-66a86e0f>Environment</code>, <code data-v-66a86e0f>Owner</code>, <code data-v-66a86e0f>CostCenter</code>). Reports missing or empty tag values. Configurable in <code data-v-66a86e0f>config.yaml</code>.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Resource Policy Checks</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>policy</code></td><td data-v-66a86e0f>Validates resources against defined policies: forbidden instance types in production, minimum backup retention, required encryption settings.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Policy Violations</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>violations</code></td><td data-v-66a86e0f>Detects resources violating governance policies: publicly exposed resources, unencrypted storage, over-privileged IAM roles.</td></tr></tbody></table></section><section class="doc-section" id="pentest" data-v-66a86e0f><h2 data-v-66a86e0f>Pentest</h2><p data-v-66a86e0f>Pentest checks simulate an attacker&#39;s perspective — finding exposed entry points, leaked secrets, and exploitable chains.</p><table class="doc-table" data-v-66a86e0f><thead data-v-66a86e0f><tr data-v-66a86e0f><th data-v-66a86e0f>Script</th><th data-v-66a86e0f>ID</th><th data-v-66a86e0f>What it does</th></tr></thead><tbody data-v-66a86e0f><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Exposed Services</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>exposed</code></td><td data-v-66a86e0f>Checks security groups and NACLs for inbound rules exposing sensitive ports (22, 3389, 3306, 5432, 1433, 27017, 6379, 9200, etc.) to the public internet.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Secrets Scan</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>secrets</code></td><td data-v-66a86e0f>Searches asset metadata (Lambda env vars, EC2 user-data, ECS task definitions) and optionally a local repo path for hardcoded secrets using regex patterns.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Exploit Mapping</strong></td><td data-v-66a86e0f><code data-v-66a86e0f>exploits</code></td><td data-v-66a86e0f>Maps findings to known exploit chains using a graph engine. Example: public-S3 + wildcard-IAM = data exfiltration path; exposed-EC2 + EKS-public-API = cluster takeover path.</td></tr></tbody></table></section><section class="doc-section" id="tests" data-v-66a86e0f><h2 data-v-66a86e0f>Tests</h2><p data-v-66a86e0f>Runs CloudRadar&#39;s built-in unit and integration test suite using <code data-v-66a86e0f>pytest</code> with mocked AWS services. Tests never make real API calls.</p><table class="doc-table" data-v-66a86e0f><thead data-v-66a86e0f><tr data-v-66a86e0f><th data-v-66a86e0f>Module</th><th data-v-66a86e0f>What it tests</th></tr></thead><tbody data-v-66a86e0f><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Rule Engine</strong></td><td data-v-66a86e0f>Security rules fire correctly and produce accurate findings with correct fields.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>S3 Scanner</strong></td><td data-v-66a86e0f>S3-specific scanner end-to-end with moto: public bucket, no encryption, permissive policy, clean bucket.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Compliance Frameworks</strong></td><td data-v-66a86e0f>All five frameworks map findings to controls correctly; pass/fail is accurate; clean environment produces all-pass report.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Remediation Engine</strong></td><td data-v-66a86e0f>Auto-remediation actions are generated correctly for each finding type.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>Attack Paths</strong></td><td data-v-66a86e0f>Attack path graph builds correctly; high-severity chains are detected; isolated resources produce no path.</td></tr><tr data-v-66a86e0f><td data-v-66a86e0f><strong data-v-66a86e0f>All Scanners</strong></td><td data-v-66a86e0f>Integration tests for every scanner module: EC2, RDS, IAM, Lambda, CloudTrail, VPC, EBS, EKS, ECS, KMS, API Gateway, SQS, DynamoDB, GuardDuty, CloudWatch.</td></tr></tbody></table></section><section class="doc-section" id="hosting" data-v-66a86e0f><h2 data-v-66a86e0f>Running CloudRadar</h2><h3 data-v-66a86e0f>Local setup</h3><ol data-v-66a86e0f><li data-v-66a86e0f>Install Python deps: <code data-v-66a86e0f>pip install -e .</code></li><li data-v-66a86e0f>Install and build frontend: <code data-v-66a86e0f>cd frontend &amp;&amp; npm install &amp;&amp; npm run build</code></li><li data-v-66a86e0f>Start the server: <code data-v-66a86e0f>python -m cspm.cli ui --host 127.0.0.1 --port 8000</code></li><li data-v-66a86e0f>Open <code data-v-66a86e0f>http://127.0.0.1:8000</code>, select your cloud, and enter credentials in Setup.</li></ol><h3 data-v-66a86e0f>Hosted on a server</h3><ol data-v-66a86e0f><li data-v-66a86e0f>Build the frontend on the server (or copy the <code data-v-66a86e0f>frontend/dist/</code> folder).</li><li data-v-66a86e0f>Run: <code data-v-66a86e0f>python -m cspm.cli ui --host 0.0.0.0 --port 8000</code></li><li data-v-66a86e0f>Put Nginx or another reverse proxy in front with HTTPS.</li><li data-v-66a86e0f>Add this to your Nginx config to prevent SSE buffering:<pre class="doc-code" data-v-66a86e0f>proxy_buffering off;
X-Accel-Buffering: no;</pre></li><li data-v-66a86e0f>Prefer IAM roles (AWS), Workload Identity (GCP), or Managed Identity (Azure) instead of storing keys in <code data-v-66a86e0f>config.yaml</code>.</li></ol><h3 data-v-66a86e0f>Docker</h3><p data-v-66a86e0f>A <code data-v-66a86e0f>docker-compose.yml</code> is included. Run <code data-v-66a86e0f>docker compose up --build</code> to start the full stack. Set credentials via environment variables or mount a <code data-v-66a86e0f>config.yaml</code> volume.</p></section>`,23)])])}const f=t(s,[["render",n],["__scopeId","data-v-66a86e0f"]]);export{f as default};
